193	        if (!check_if_all_features_are_supported(required_features)) {
194	            fprintf(stderr, "[FlashMLA] Error: The chosen implementation does not support all required features.\n");
195	            fprintf(stderr, "Required features:\n");
196	            for (const auto &f : required_features) {
197	                fprintf(stderr, "  - %3d: %s\n", static_cast<int>(f), get_dynamic_enum_name(f).c_str());
198	            }
199	            fprintf(stderr, "\n");
200	            fprintf(stderr, "Supported features:\n");
201	            for (const auto &supported_feature : get_supported_features()) {
202	                fprintf(stderr, "  - %3d: %s\n", static_cast<int>(supported_feature), get_dynamic_enum_name(supported_feature).c_str());
203	            }
204	            fprintf(stderr, "\n");
205	            fprintf(stderr, "Features that are required but not supported:\n");
206	            for (const auto &required_feature : required_features) {
207	                bool is_supported = false;
208	                for (const auto &supported_feature : get_supported_features()) {
209	                    if (required_feature == supported_feature) {
210	                        is_supported = true;
211	                        break;
212	                    }
213	                }
214	                if (!is_supported) {
215	                    fprintf(stderr, "  - %3d: %s\n", static_cast<int>(required_feature), get_dynamic_enum_name(required_feature).c_str());
216	                }
217	            }
218	            fprintf(stderr, "\n");
